import json
# --- reproduce the per-criterion ledger for all three targets, through the harness's own weighting ---
p='third_party/deep_research_bench/data/criteria_data/criteria.jsonl'
W={}
for line in open(p):
    d=json.loads(line)
    if str(d['id'])!='72': continue
    for dim,items in d['criterions'].items():
        tot=sum(c['weight'] for c in items) or 1.0
        for c in items:
            W[(dim,c['criterion'])]=(c['weight']/tot)*d['dimension_weight'][dim]
    break
print('n criteria:', len(W), ' sum(w) =', round(sum(W.values()),6))
print()

def ledger(f):
    fb=json.load(open(f)); out={}
    for dim,items in (fb['judge_output'] or {}).items():
        if isinstance(items,list):
            for c in items: out[(dim,c['criterion'])]=(c['article_1_score'],c['article_2_score'])
    return out

L={n:ledger(f) for n,f in [('POLARIS','outputs/judge_feedback.json'),('BODHI','outputs/judge_feedback_bodhi.json'),('CELLCOG','outputs/judge_feedback_cellcog.json')]}
for n,l in L.items():
    T=sum(l[c][0]*W[c] for c in l if c in W); R=sum(l[c][1]*W[c] for c in l if c in W)
    print(f'{n:8} T={T:.4f}  R={R:.4f}  overall={T/(T+R):.4f}  ncrit={len(l)}')
print()
print('=== THE FULL 25-CRITERION GAP MAP (sorted by w*headroom vs cellcog) ===')
print(f'{\"w\":>6} {\"dim\":<12} {\"criterion\":<52} {\"us\":>5} {\"bod\":>5} {\"cell\":>5} {\"ref\":>5} {\"w*(cell-us)\":>11}')
rows=[]
for c in W:
    us=L['POLARIS'].get(c,(None,None))[0]; ref=L['POLARIS'].get(c,(None,None))[1]
    bo=L['BODHI'].get(c,(None,None))[0]; ce=L['CELLCOG'].get(c,(None,None))[0]
    if us is None or ce is None: continue
    rows.append((W[c]*(ce-us), W[c], c[0], c[1], us, bo, ce, ref))
rows.sort(reverse=True)
for g,w,dim,cr,us,bo,ce,ref in rows:
    print(f'{w:6.4f} {dim[:12]:<12} {cr[:52]:<52} {us:5.1f} {str(bo):>5} {ce:5.1f} {ref:5.1f} {g:11.4f}')
print()
print('sum w*(cell-us) [raw T gain if we matched cellcog everywhere] =', round(sum(r[0] for r in rows),4))
"
